import type { PieceTexte } from '../pieceTextes';

const texte: PieceTexte = {
  source: 'Sophocle, Œdipe roi — traduction française de Nicolas Artaud, Charpentier, 1859. Source : Wikisource, domaine public.',
  blocs: [
    { k: 'acte', t: 'ŒDIPE ROI' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Enfants, jeune postérité de l’antique Cadmus, quel empressement vous rassemble sur ces degrés, portant dans vos mains les rameaux des suppliants ? L’encens des sacrifices fume dans toute la ville, qui retentit à la fois d’hymnes et de gémissements. Ne voulant point apprendre vos malheurs d’une voix étrangère, je suis venu moi-même ici, moi, cet Œdipe dont le nom est dans toutes les bouches. Dis-moi donc, vieillard, toi à qui il appartient de parler au nom des autres, dis-moi quel motif vous rassemble ; est-ce la crainte ? est-ce pour implorer les dieux ? Mon désir est de vous être secourable ; car il faudrait que je fusse insensible, pour n’être pas ému de pitié par un tel spectacle.' },
    { k: 'perso', t: 'LE GRAND PRÊTRE' },
    { k: 'ligne', t: 'Œdipe, souverain de mon pays, tu vois quelle foule se presse autour des autels devant ton palais ; des enfants' },
    { k: 'ligne', t: 'qui peuvent à peine se soutenir, des prêtres appesantis par la vieillesse, et moi, pontife de Jupiter, et l’élite de la jeunesse ; le reste du peuple, portant des branches d’olivier, se répand sur les places publiques, devant les deux temples de Pallas, près de l’autel prophétique de l’Isménos. Car Thèbes, tu le vois toi-même, trop longtemps battue par l’orage, ne peut plus soulever sa tête de la mer de sang où elle est plongée ; la mort atteint les germes des fruits dans les entrailles de la terre ; la mort frappe les troupeaux, et fait périr l’enfant dans le sein de sa mère ; une divinité ennemie, la peste dévorante, ravage la ville et dépeuple la race de Cadmus ; le noir Pluton s’enrichit de nos pleurs et de nos gémissements. Ce n’est pas que nous t’égalions aux dieux, quand nous venons, ces enfants et moi, implorer ton secours, mais nous voyons en toi le premier des mortels pour conjurer les malheurs de la vie, et la colère des dieux : c’est toi qui, en paraissant dans la ville de Cadmus, l’as affranchie du tribut qu’elle payait au sphinx cruel, et cela, sans être instruit ni éclairé par nous ; mais avec l’aide des dieux, chacun le dit et le' },
    { k: 'ligne', t: 'pense, tu devins notre libérateur. Aujourd’hui encore, Œdipe, toi dont tous révèrent la puissance, nous venons en suppliants te conjurer de trouver quelque remède à nos maux, soit qu’un Dieu t’éclaire de ses oracles, ou un homme de ses avis ; car, je le vois, les conseils des hommes expérimentés ont toujours le plus de succès. Viens, ô le meilleur des mortels, relever cette ville abattue ; allons, veille sur nous, car c’est toi qu’aujourd’hui cette cité appelle son Sauveur, pour tes services passés. Puisse ton règne ne jamais nous rappeler qu’après avoir été sauvés par toi, tu nous as laissés retomber dans l’abîme ! Rends-nous donc la sécurité, et relève cette ville abattue. Ces heureux auspices sous lesquels tu rétablis alors notre fortune, ne les démens pas aujourd’hui. Car si tu dois continuer à gouverner ce pays, mieux vaut régner sur des citoyens que sur un pays vide d’habitants. Qu’est-ce en effet qu’une forteresse sans soldats, et un navire sans matelots ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Enfants bien dignes de pitié, je ne connais que trop le vœu qui vous amène ; oui, je le sais, vous souffrez tous, et, dans cette commune souffrance, aucun de vous ne souffre autant que moi. Car chacun de vous ne ressent que sa propre douleur, et non celle des autres ; mais mon cœur pleure tout ensemble les maux de Thèbes, les vôtres et les miens. Aussi n’avez-vous pas eu à éveiller ma vigilance endormie ? mais sachez que j’ai déjà versé bien des larmes, et mon esprit inquiet a tenté plus d’une voie de salut. Le seul remède que la réflexion m’a découvert, je l’ai mis en œuvre : le fils de Ménécée, Créon, mon beau-frère, est allé, par mon ordre, au temple de Delphes, demander au dieu par quels vœux ou par quels sacrifices je pourrais sauver cette ville. Déjà je calcule le temps écoulé depuis son départ, et je m’inquiète de son' },
    { k: 'ligne', t: 'absence ; car elle se prolonge plus qu’elle ne devrait. Mais quand il sera de retour, je serais alors bien coupable, si je n’exécutais tous les ordres du dieu.' },
    { k: 'perso', t: 'LE GRAND PRÊTRE' },
    { k: 'ligne', t: 'C’est fort à propos que tu en parles, car voici qu’on m’annonce l’arrivée de Créon.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Divin Apollon, puisse son heureux retour nous apporter le salut, que son air radieux semble présager !' },
    { k: 'perso', t: 'LE GRAND PRÊTRE' },
    { k: 'ligne', t: 'Selon les apparences, il est joyeux ; autrement il ne viendrait pas ainsi, la tête couronnée de laurier.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Nous le saurons bientôt, il est assez près pour entendre. Fils de Ménécée, toi qui m’es uni par les liens du sang, quelle réponse nous apportes-tu de la part du dieu ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Favorable ; car cette crise même, si nous savons habilement la mener à fin, se changera en prospérité.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Que signifie ce langage ? En effet ces paroles que tu profères n’excitent ni ma confiance ni mes appréhensions.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Si tu désires m’entendre en présence de cette foule, je suis prêt à parler, ou bien à te suivre dans le palais.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Parle en présence de tous ; car leur malheur me touche' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Je dirai donc la réponse que j’ai reçue du dieu. Apollon nous enjoint clairement de chasser de cette terre un monstre qui la souille, et qu’elle nourrit dans son sein, et de ne pas y souffrir plus longtemps sa présence inexpiable.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Quelle expiation devons-nous faire ? quelle est la nature de ce fléau ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Il faut bannir le coupable, ou punir le meurtre par un meurtre, car le sang versé déchaîne la tempête sur notre ville.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Quel est donc l’homme dont il rappelle le meurtre ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Prince, Laïus régnait autrefois sur cette contrée, avant que tu en fusses le roi.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'On me l’a dit ; car mes yeux ne l’ont jamais vu.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Il a péri, et maintenant le dieu nous enjoint clairement de punir ses meurtriers.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Mais où sont-ils ? où découvrir la trace effacée d’un crime si ancien ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ils sont en ce pays, a dit le dieu. Ce que l’on cherche, on le trouve ; mais ce qu’on néglige nous échappe.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Est-ce dans la ville ? est-ce à la campagne, ou sur une terre étrangère, que le meurtre de Laïus a été commis ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Il était parti, disait-il, pour aller consulter l’oracle, et depuis son départ il n’a plus reparu dans sa patrie.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Mais n’y eut-il ni messager, ni compagnon de voyage de Laïus, témoin du fait, qui pût donner des indices et aider les recherches ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ils ont péri, à l’exception d’un seul, que la peur a fait fuir, mais il n’a pu dire qu’une chose de ce qu’il a vu.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Laquelle ? car un seul fait peut en faire découvrir bien d’autres, s’il nous donne une lueur d’espérance.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Des brigands l’assaillirent, dit-il, et il succomba, non sous le bras d’un seul, mais accablé par le nombre.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Comment donc un brigand, s’il n’avait été suborné par quelqu’un d’ici, aurait-il eu cette audace ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Tels furent alors les soupçons ; mais, au milieu de nos maux, la mort de Laïus n’eut point de vengeur.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Quels maux vous empêchèrent donc, après ce meurtre de votre roi, de rechercher les auteurs du crime ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Le sphinx, avec ses énigmes, en nous occupant d’un' },
    { k: 'ligne', t: 'mal présent, nous fit oublier un crime encore obscur.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Eh bien ! je remonterai à la source du fait, et le mettrai en lumière. Il est digne d’Apollon, il est digne de toi, d’avoir montré cette sollicitude pour celui qui a péri, vous trouverez donc en moi un auxiliaire légitime, vengeur à la fois de ce pays et du dieu. Ce n’est pas pour un ami étranger, c’est pour moi-même que j’effacerai cette souillure. Le meurtrier, quel qu’il soit, voudrait peut-être aussi porter sur moi sa main homicide ; en vengeant Laïus, je me défends donc moi-même. Enfants, relevez-vous au plus tôt, et remportez ces rameaux suppliants ; qu’un autre assemble ici le peuple de Cadmus ; je suis prêt à tout faire. Car ou nous serons heureux en obéissant au dieu, ou nous tomberons dans l’abîme du malheur.' },
    { k: 'perso', t: 'LE GRAND PRÊTRE' },
    { k: 'ligne', t: 'Enfants, levons-nous ; le secours que nous sommes venus demander ici, le roi nous l’annonce. Puisse Apollon, qui nous envoie ces oracles, être notre sauveur, et mettre fin au fléau qui nous désole !' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Strophe 1.) O douce parole de Jupiter, échappée du riche sanctuaire de Delphes, que viens-tu annoncer enfin à la brillante ville de Thèbes ? Saisi d’une sainte horreur, mon cœur frémit, il palpite d’effroi, ô Apollon, dieu de Délos, médecin de tous les maux, attendant avec un respect religieux le sort que tu me réserves maintenant ou dans l’avenir. Réponds-moi, fils de la riante espérance, Oracle immortel.' },
    { k: 'ligne', t: '(Antistrophe 1.) C’est toi que j’invoque la première, fille de Jupiter, immortelle Minerve, et toi, Diane, sa sœur, protectrice de cette terre, assise au sein des murs de Thèbes sur un trône glorieux, toi aussi, redoutable Apollon ! venez tous trois nous secourir ; si jamais, lorsqu’un monstre cruel planait sur notre cité, vous l’avez délivrée de ce fléau destructeur, venez encore aujourd’hui.' },
    { k: 'ligne', t: '(Strophe 2.) Grands dieux ! je souffre des maux innombrables ; tout mon peuple languit, et toute la science humaine est impuissante à le secourir ; en effet, les germes ne mûrissent plus dans le sein de la terre, les mères ne peuvent supporter les cruelles douleurs de l’enfantement ; on peut voir les morts tomber l’un après l’autre sur le rivage du dieu des ténèbres, plus vite que l’oiseau rapide, ou que la flamme indomptable.' },
    { k: 'ligne', t: '(Antistrophe 2.) Leurs innombrables funérailles dépeuplent la ville ; des monceaux de cadavres, privés de sépulture, gisent, sans être pleurés, sur la terre où règne la mort ; de tendres épouses, des mères blanchies par l’âge, prosternées çà et là au pied des autels, implorent en gémissant le terme de leurs souffrances. Le son éclatant des pæans se mêle aux accents des voix plaintives. Par pitié pour elles, auguste fille de Jupiter, envoie-nous un secours consolateur.' },
    { k: 'ligne', t: '(Strophe 3.) Mets en fuite ce dieu funeste, ce Mars cruel qui, sans fer et sans armes, m’attaque à grands' },
    { k: 'ligne', t: 'cris, et me brûle de ses feux, rejette-le loin de ma patrie, soit dans le vaste sein d’Amphitrite, ou sur les bords inhospitaliers de la mer de Thrace ; ce que la nuit a épargné, le jour le consume ; ô toi qui disposes de la foudre étincelante, ô Jupiter, écrase-le sous ton tonnerre.' },
    { k: 'ligne', t: '(Antistrophe 3.) Dieu destructeur des loups, puisse ton arc aux cordes d’or lancer tes flèches invincibles et protectrices pour nous défendre, et Diane faire briller ses torches ardentes, avec lesquelles elle parcourt les montagnes de la Lycie ! O toi qui tires ton origine de ce pays, et dont une mitre d’or ceint le front, je t’invoque, riant Bacchus, compagnon des Ménades, viens avec une torche enflammée combattre le plus abhorré des dieux !' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Vous avez formé un vœu, et l’objet de ce vœu, si vous voulez écouter mes conseils, et faire ce qu’exige la nature du fléau, vous pourrez l’obtenir, (je veux dire) un remède et un soulagement à vos maux ; pour moi, étranger à ce qui a été dit de Laïus, étranger au crime, je partirai ; voici ce que j’ai à vous dire, car je ne saurais aller loin dans mes recherches, si je n’obtenais de vous quelque indice. Maintenant, moi qui compte récemment au nombre des citoyens, voici ce que je proclame à vous tous, habitants de la ville de Cadmus : Si l’un de vous sait quelle main a tranché les jours de Laïus, fils de Labdacos, qu’il me révèle tout, je l’ordonne ; et si la crainte retient le coupable, qu’il se dérobe à l’accusation en s’accusant lui-même, et se retire sain et sauf de ce pays, car il ne lui sera pas fait d’autre mal. Ou bien, si l’un de vous sait que le meurtrier vit sur une terre étrangère, qu’il parle ; je lui promets récompense, et, de plus, ma reconnaissance lui est assurée. Mais si vous gardez le' },
    { k: 'ligne', t: 'silence, si, par crainte pour soi-même ou pour un ami, on se refuse à mon ordre, apprenez donc ce que je ferai dès lors. Cet homme, quel qu’il soit, je défends à tout habitant de cette contrée où je règne, de le recevoir, de lui adresser la parole, de l’admettre aux prières et aux sacrifices divins, de lui présenter l’eau lustrale ; que tous le repoussent de leurs maisons, comme le fléau de la patrie ; ainsi me l’a ordonné naguère l’oracle du dieu qu’on adore à Delphes. En agissant ainsi, j’obéis au dieu, et je venge le roi qui n’est plus. Je maudis l’auteur caché du crime, soit qu’il l’ait commis seul, ou qu’il ait eu des complices ; et que, proscrit partout, il traîne misérablement sa vie. Et s’il est admis dans mon palais, à mon foyer, et de mon consentement, je me voue moi-même aux imprécations que je lançais tout à l’heure contre les coupables. C’est à vous, Thébains, d’exécuter tous ces ordres, pour venger le dieu, et moi-même, et cette terre, frappée de stérilité et de la colère céleste. Et lors même que la recherche du meurtrier n’aurait pas été commandée par les dieux, il ne vous convenait point de laisser sans expiation un crime qui vous a ravi votre roi, le meilleur des hommes ; non, il fallait rechercher le coupable. Mais aujourd’hui que je suis monté sur le trône qu’il occupait, et que j’ai reçu la main de son épouse, et que mes enfants et les siens seraient frères, s’ils avaient vécu, mais la fortune était déchaînée contre lui ; à tous ces titres, je vengerai sa mort comme celle de mon père, et je ferai tout pour découvrir le meurtrier du fils de' },
    { k: 'ligne', t: 'Labdacos, du descendant de Polydore, de Cadmus et du vieil Agénor. Ceux qui refuseront de souscrire à mes ordres, fassent les dieux qu’ils voient leurs champs sans moissons et leurs épouses sans enfants ! mais qu’ils meurent du fléau qui nous désole, ou d’une mort encore plus affreuse ! Quant à vous, Thébains, qui approuvez mes desseins, que toujours la Justice vous protège, et que tous les dieux vous soient favorables !' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Puisque tes imprécations m’y contraignent, je parlerai ; je n’ai pas tué Laïus, et je ne puis indiquer le meurtrier. Et quant à sa recherche, c’était à Phébus, qui l’a ordonnée, à faire connaître l’auteur du crime.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tu dis vrai ; mais contraindre les dieux à faire ce qu’ils ne veulent point n’est pas au pouvoir d’un mortel.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Je pourrais te proposer un second avis, qui me semble bon.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Si même tu en as un troisième, ne crains pas de le dire.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Le puissant Tirésias, je le sais, partage avec le puissant Apollon la science de l’avenir, et, en l’interrogeant, on pourrait obtenir de lui d’importantes révélations.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je n’ai pas négligé non plus cette voie. En effet, sur l’avis de Créon, j’ai envoyé vers lui un double message, et je m’étonne qu’il tarde si longtemps.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Quant aux autres bruits qui ont couru, ils sont sans fondement et surannés.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Quels sont ces bruits ? je veux approfondir tout ce qui se dit.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je l’ai aussi entendu dire ; mais personne ne connaît de témoin.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Mais le coupable, s’il est accessible à la crainte, lorsqu’il connaîtra tes imprécations si terribles, ne persistera-t-il pas dans son silence ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Celui que le crime n’effraie point, ne craint pas les paroles.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Mais il y a quelqu’un qui saura bien le découvrir ; voici en effet qu’on amène ici le divin prophète, qui, seul entre les mortels, a le don de la vérité.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'O Tirésias, toi dont l’esprit embrasse tout, et les sciences humaines et les secrets des dieux, et les choses du ciel et celles de la terre, bien que privé de la vue, tu sais cependant quel fléau désole cette cité ; en toi seul, ô prince, nous trouvons pour elle un appui et un sauveur. Apollon, si mes envoyés ne te l’ont pas appris, a répondu à notre demande, que le seul remède à cette contagion serait de découvrir les meurtriers de Laïus, et de les faire périr, ou de les bannir de cette contrée. Toi donc, ne nous refuse pas ton secours, consulte le vol des oiseaux et les autres ressources de l’art prophétique, sauve Thèbes et toi-même, sauve-moi, et purifie-nous de toutes les souillures du meurtre. Car en toi est notre espoir ; servir les hommes, de toutes les ressources que donnent le savoir et la puissance, est le plus glorieux des travaux.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Hélas ! hélas ! que la science est un présent funeste,' },
    { k: 'ligne', t: 'lorsqu’elle ne profite pas à celui qui la possède ! Je le savais et je l’ai oublié ! autrement je ne serais pas venu ici.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Qu’y a-t-il ? En quel découragement tu nous arrives !' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Laisse-moi repartir ; car toi et moi nous porterons plus facilement le fardeau de nos peines, si tu veux m’en croire.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tu as tort de parler ainsi, et c’est manquer d’amour pour cette ville qui t’a nourri, que lui refuser l’explication de l’oracle.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'C’est que je vois que tu parles hors de propos ; je me tais donc, pour ne pas encourir le même reproche.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Au nom des dieux, ne nous dérobe pas ce que tu sais, tu nous vois tous à tes pieds, en suppliants.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'C’est que vous êtes tous dans le délire ; mais moi, non, jamais je ne révélerai mes misères, pour ne pas révéler les tiennes.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Que dis-tu ? tu sais tout, et tu refuses de parler ! tu veux donc nous trahir, et ruiner Thèbes de fond en comble ?' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Je ne veux affliger ni toi, ni moi-même. Pourquoi m’interroger inutilement ? tu n’apprendras rien de moi.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'O le plus pervers des hommes (car enfin ta résistance irriterait un rocher), ne parleras-tu pas enfin ? tu resteras' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Tu me reproches des paroles irritantes, mais tu ne vois pas ce qui chez toi irrite les autres, et pourtant tu m’outrages.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Et qui ne s’irriterait d’entendre un tel langage, et du mépris que tu montres pour cette cité ?' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Ce fatal secret se révélera de lui-même, malgré le silence dont je le couvre.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Si donc il doit se révéler, il est bien juste que tu me le dises à moi-même.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Je n’ajouterai pas un mot. Après quoi, livre-toi aux accès de ta farouche colère.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Eh bien ! oui, tant je suis en colère, je n’omettrai rien, de tout ce que je pense. Sache donc que tu me parais avoir conçu comme la pensée du crime, et l’avoir accompli, si ce n’est que ta main n’a pas porté le coup ; et si tu n’étais privé de la lumière, je t’accuserais de l’avoir commis à toi seul.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Vraiment ? et moi je t’ordonne de te conformer à l’arrêt que tu as prononcé, et dès ce jour de ne parler ni à moi, ni à aucun des Thébains, car tu es l’impie qui souille cette terre.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Oses- tu bien proférer des paroles si imprudentes ? et crois-tu échapper au châtiment qu’elles méritent ?' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Et qui te l’a apprise ? Assurément ce n’est point ton art.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Toi-même ! car c’est toi qui m’as contraint à parler,' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Qu’as-tu dit ? répète-le encore, pour que je le sache mieux. Je veux la bien savoir.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'N’as-tu pas entendu la première fois ? ou veux-tu m’éprouver ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Non, pas assez pour dire que je le sache ; répète donc.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Je te dis que tu es ce meurtrier de Laïus que tu cherches.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ah ! tu ne m’outrageras pas deux fois impunément !' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Faut-il donc t’en dire davantage pour redoubler ta colère ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Dis tout ce qu’il te plaira ; tes propos seront vains.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Je te le déclare, tu ignores les horribles nœuds que tu as formés avec ce que tu as de plus cher, et tu ne connais pas tout ton malheur.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Penses-tu donc que ces injures resteront toujours impunies ?' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Oui, elle en a, mais non dans ta bouche, tu ne peux l’invoquer, toi, dont les yeux, les oreilles et l’esprit sont à jamais fermés.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Tu es bien malheureux, de me reprocher ce que bientôt chaque Thébain te reprochera à toi-même.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Toi qui vis dans d’éternelles ténèbres, tu ne saurais nuire ni à moi, ni à aucun de ceux qui voient la lumière.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'En effet, ton destin n’est point de tomber sous mes coups. Apollon suffit, c’est lui que la vengeance regarde.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ces inventions sont-elles de Créon ou de toi ?' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Ce n’est pas Créon qui cause ton malheur, mais toi seul en es l’auteur.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'O richesse, pouvoir suprême, sagesse qui nous élèves au-dessus des autres, dans cette vie remplie de tant de rivalités, combien vous êtes exposés à l’envie, si, pour cet empire que les Thébains m’ont déféré de leur propre choix, sans que je l’aie demandé, Créon, cet ancien, ce fidèle ami, trame contre moi des intrigues secrètes, dans le désir de me renverser, et suborne ce misérable' },
    { k: 'ligne', t: 'devin, cet artisan de fraudes, ce charlatan, clairvoyant pour le gain seul, mais aveugle dans son art. Car enfin, dis-moi, où as-tu été bon prophète ? Lorsque le sphinx proposait ici ses énigmes, comment n’as-tu pas donné aux Thébains quelque moyen de s’en délivrer ? cependant il n’appartenait pas au premier venu d’expliquer l’énigme, c’était la tâche du devin ; ni le vol des oiseaux, ni aucun des dieux, ne t’en ont fait pénétrer le sens ; mais moi, mortel ignorant, à peine arrivé dans Thèbes, j’ai confondu le monstre par le seul secours de ma raison, et sans consulter le vol des oiseaux. Aujourd’hui tu travailles à me renverser, dans l’espoir de prendre place auprès du trône de Créon ; mais ce ne sera pas impunément, je pense, que toi et l’auteur de ces intrigues vous prétendez me chasser comme un être impur ; et si je n’excusais ta vieillesse, tu connaîtrais déjà le châtiment que mérite ton délire.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'A notre sens, ses paroles et les tiennes, Œdipe, nous paraissent dictées par la colère. Il faut faire trêve à de pareils débats, nous devons seulement songer aux meilleurs moyens d’accomplir l’oracle du dieu.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Bien que tu sois roi, Œdipe, il y a cependant cette égalité entre nous, que je puis te répondre ; car moi aussi j’en ai le droit. Je ne suis pas ton sujet, mais celui d’Apollon ; je n’ai point Créon pour patron, et ne suis pas inscrit au nombre de ses clients. Tu me reproches d’être aveugle ; mais toi, malheureux, toi qui jouis de la lumière, tu ne vois pas en quel abîme de maux tu es tombé, ni où tu habites, ni avec qui tu demeures. Sais-tu qui t’a donné le jour ? Tu ignores ce qui te rend exécrable à tes proches, sur la terre, et à ceux des tiens qui' },
    { k: 'ligne', t: 'sont dans les enfers. Armée d’un double fouet, la malédiction de ta mère et de ton père, déesse à la marche terrible, te rejettera de cette contrée, et si tu vois clair maintenant, bientôt tes yeux ne verront que les ténèbres. Quel asile ne retentira pas de tes cris ? Quel antre du Cithéron ne les répétera pas, lorsque lu connaîtras l’hymen fatal, écueil où est venu échouer ton bonheur ! Tu ne sais pas l’orage de maux qui fondra sur toi, et qui, en te montrant qui tu es, te rendra l’égal de tes enfants. Maintenant donc déchaîne tes outrages contre Créon et contre mes paroles ; car jamais nul mortel ne sera plus misérablement que toi accablé par le sort.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Est-il donc possible de supporter ces outrages d’une telle bouche ? Malédiction sur toi ! Ne partiras-tu pas au plus tôt ? Ne t’éloigneras-tu pas enfin de ces lieux ?' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Je ne serais point venu, si tu ne m’avais appelé.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'C’est que je ne savais pas que tu tiendrais des discours insensés, autrement je ne me serais pas pressé de te faire venir dans mon palais.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Voilà donc ce que je suis, à ce qu’il te semble, un insensé ;' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Quels parents ? Arrête : quel mortel m’a donné la vie !' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Ce jour va te donner la naissance et la mort.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Comme toutes tes paroles sont énigmes obscures !' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'N’excelles-tu pas dans l’art de les expliquer ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Reproche-moi un fait où tu trouveras la preuve de ma grandeur.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'C’est pourtant cette fortune même qui t’a perdu.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Si du moins j’ai sauvé Thèbes, peu m’importe le reste.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Eh bien ! je me retire. Enfant, conduis-moi.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Qu’il t’emmène donc ; car ta présence me trouble et m’importune ; une fois parti, tu ne me fatigueras plus.' },
    { k: 'perso', t: 'TIRÉSIAS' },
    { k: 'ligne', t: 'Je partirai, mais après avoir dit ce qui m’amenait ici, et sans craindre ton visage menaçant ; car il n’est pas en ton pouvoir de me faire périr. Je te le dis donc, cet homme que tu cherches avec tant de menaces, par tes édits contre le meurtrier de Laïus, il est dans Thèbes, où il passe pour étranger, mais bientôt il sera reconnu pour Thébain indigène ; il n’aura pas à se réjouir de l’aventure. Car il perdra la vue, il perdra ses richesses, aveugle et pauvre, il errera sur une terre étrangère, cherchant sa route, le bâton à la main. Il sera reconnu pour être' },
    { k: 'ligne', t: 'à la fois le frère et le père de ses propres enfants, le fils et l’époux de la femme qui lui a donné le jour, et le meurtrier de son père, dont il a souillé la couche. Maintenant, rentre dans ton palais, et réfléchis à ces paroles ; et si tu me prends en mensonge, dis alors que je n’entends rien à la divination.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Strophe 1.) Quel est celui que le rocher prophétique de Delphes accuse d’avoir commis de ses mains homicides les crimes les plus inouïs ? Il est temps pour lui de précipiter sa fuite plus promptement que les coursiers rapides. Car déjà le fils de Jupiter fond sur lui, armé de foudres et d’éclairs ; et en même temps les Furies cruelles et inévitables le poursuivent.' },
    { k: 'ligne', t: '(Antistrophe 1.) En effet, des neiges du Parnasse est partie naguère la voix éclatante qui ordonne à tous de chercher les traces du coupable inconnu. Comme un taureau sauvage, il va dans les bois, au fond des antres et des rochers, traînant ses pas infortunés en des lieux solitaires, pour se dérober à l’oracle sorti du centre de la terre ; mais cette voix immortelle vole autour de lui.' },
    { k: 'ligne', t: '(Strophe 2.) Cependant l’habile devin me jette dans un trouble terrible, oui terrible ; dois-je croire ou rejeter' },
    { k: 'ligne', t: 'ses paroles ? je ne sais que penser ; mon esprit en suspens ne voit rien dans le présent ni dans le passé qui puisse fixer ses incertitudes. Car quel différend s’est jamais élevé entre les Labdacides et le fils de Polybe ? je n’en ai jamais rien appris, ni jadis, ni aujourd’hui, qui m’autorise à attaquer la renommée si populaire d’Œdipe, pour venger les Labdacides d’un meurtre dont l’auteur est inconnu.' },
    { k: 'ligne', t: '(Antistrophe 2.) Cependant Jupiter et Apollon sont sages, et lisent dans les cœurs des mortels ; mais qu’entre tous les hommes un devin en sache plus que moi, voilà ce que rien ne prouve. Un mortel peut en surpasser un autre en sagesse ; mais jamais je n’ajouterai foi à ceux qui attaquent Œdipe, avant d’avoir des preuves évidentes. Quand jadis la vierge ailée nous apparut, sa sagesse fut reconnue, et il sortit de cette épreuve le sauveur de notre ville : aussi, à mon sens, n’encourra-t-il jamais l’accusation d’impiété.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Citoyens, informé qu’Œdipe porte contre moi les accusations les plus graves, je viens, pénétré d’une douleur que je ne puis supporter. Si, au milieu de nos malheurs présents, il croit avoir souffert quelque dommage de mes paroles ou de mes actions, je ne saurais plus vivre, chargé d’une telle imputation ; car ce serait pour moi le plus grand et le plus sensible des outrages, de passer pour traître aux yeux de Thèbes, de mes amis et de vous.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Cette injure a été sans doute arrachée par la colère, bien plus qu’elle ne part de la conviction.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Mais sur quel indice a-t-il cru que mes conseils ont' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Il l’a dit, il est vrai ; mais j’ignore sur quelles preuves.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Est-ce d’un regard assuré et de sang-froid qu’il a lancé contre moi cette accusation ?' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Je ne sais ; car je n’examine point les actions des rois. Mais le voici lui-même qui sort de son palais.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Eh quoi ! comment oses-tu paraître en ces lieux ? As-tu assez d’audace et d’impudence pour venir dans mon palais, toi qui veux m’égorger moi-même au grand jour, et me voler ouvertement mon trône ? Dis-moi donc, au nom des dieux, pour machiner ce complot, as-tu remarqué en moi de la lâcheté ou de la démence ? Ou te flattais-tu que je ne découvrirais pas ton intrigue, ourdie par la ruse, ou qu’après l’avoir découverte, je ne t’en punirais pas ? N’est-ce pas de ta part une entreprise insensée, de vouloir, sans amis et sans l’appui du peuple, usurper un trône, qui ne s’obtient que par la richesse et par l’appui du peuple ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Sais-tu ce qu’il faut faire ? Laisse-moi répondre à tes accusations ; puis, une fois éclairé, juge toi-même.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tu es habile à parler ; mais je suis peu disposé à t’entendre,' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Là-dessus, écoute d’abord ce que j’ai à te dire.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Là-dessus, ne t’avise pas de me dire que tu n’es pas un traître.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Si tu penses que l’entêtement dépourvu de raison est un mérite, tu t’abuses étrangement.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Si tu penses que ton crime envers un parent doive rester impuni, tu t’abuses également.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ce que tu dis est juste, j’en conviens ; mais apprends-moi quel est le tort dont tu m’accuses envers toi.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Est-ce toi, ou non , qui m’as conseillé, comme une chose nécessaire, de mander ce fameux prophète ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Et à présent encore je persiste dans mon avis.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Combien de temps s’est-il passé depuis que Laïus....' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Que veux-tu dire ? car je ne comprends pas.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'A disparu, frappé du coup mortel ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Le crime est ancien, de longues années se sont passées depuis.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Alors, ce devin exerçait-il son art ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Il était également habile, et aussi respecté qu’aujourd’hui.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Non, du moins jamais en ma présence.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Et ne fîtes-vous aucune recherche sur le meurtre ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'On en fit, il n’en pouvait être autrement ; mais on ne découvrit rien.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Comment donc cet habile devin ne fit-il pas alors ces révélations ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Je ne sais, et j’ai l’habitude de me taire sur ce que j’ignore.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Il est au moins une chose que tu sais, et tu la diras si tu es sage.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Quelle est cette chose ? si je la sais, je ne refuserai point de la dire.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'C’est que s’il n’eût été d’accord avec toi, jamais Tirésias ne m’eût accusé du meurtre de Laïus.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'S’il le dit, tu le sais toi-même ; je désire t’interroger à ton tour comme tu viens de m’interroger.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Parle ; on ne découvrira pas en moi un meurtrier.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Eh bien donc ! n’as-tu pas épousé ma sœur ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je ne saurais nier ce que tu dis là.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Tu partages avec elle le trône et le gouvernement de ce pays.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Et moi, ne suis-je donc pas associé à votre puissance ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'C’est là précisément en quoi se montre ta perfidie.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Nullement, si tu veux réfléchir ainsi que moi. Considère d’abord ceci, penses-tu que personne préférât un trône entouré de terreurs, à une vie paisible armé de la même puissance ? Pour moi, je désire moins avoir le titre de roi, que d’en exercer le pouvoir, et ainsi pense tout homme modéré. Maintenant je vis sans crainte, et j’obtiens tout de toi ; mais si je régnais moi-même, je ferais beaucoup de choses contre mon gré. Comment donc la royauté me serait-elle plus chère qu’un pouvoir et une autorité exempts de soucis ? Je ne suis pas encore assez aveugle pour désirer autre chose, quand j’ai à la fois honneur et profit. Maintenant tous sont aimés de moi, je suis aimé de tous, maintenant ceux qui ont besoin de toi me caressent, car le succès de leurs vœux dépend de moi. Comment donc, pour être roi, sacrifierais-je ces avantages ? Un esprit sensé ne peut s’égarer ainsi. Non, je ne suis point séduit par un tel projet, et jamais je n’aurai l’audace de le tenter avec un complice. Pour t’en convaincre, va t’informer à Delphes si je t’ai fidèlement rapporté l’oracle ; et encore, si tu me trouves d’intelligence avec le devin, donne-moi la mort, je me condamne moi-même, et joins mon arrêt au tien. Mais ne m’accuse pas sur d’obscurs indices, sans m’entendre. Il n’est pas juste de prendre indistinctement les méchants pour des gens de bien, ni les gens de bien pour des méchants. En effet, rejeter un ami fidèle, c’est autant que sacrifier sa vie, le plus précieux des biens. Mais avec le temps' },
    { k: 'ligne', t: 'tu le reconnaîtras sans nul doute, car le temps seul est l’épreuve du juste ; et un seul jour aussi te fera connaître le méchant.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'O roi, son langage est raisonnable aux yeux de quiconque veut éviter les faux pas ; car ceux qui sont prompts à résoudre sont sujets à l’erreur.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Quand celui qui me tend de secrètes embûches est prompt à m’attaquer, je dois être à mon tour prompt dans mes résolutions. Mais si j’attends sans agir, ses desseins s’accompliront, et les miens seront confondus.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Que veux-tu donc ? Est-ce mon exil de ce pays ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Nullement. C’est ta mort, et non ton exil, que je veux.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Fais-moi connaître d’abord les motifs de ta haine.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Est-ce pour me résister et me désobéir que tu parles ainsi ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'C’est que je te vois si peu raisonnable.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je le suis pour mes intérêts.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Mais il faut l’être également pour les miens.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Mais tu es un traître.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Et si tu te trompais ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tu n’en dois pas moins obéir à mes ordres.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Non, si tes ordres sont injustes.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Moi aussi, je puis l’invoquer comme toi.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Arrêtez, princes ! mais voici fort à propos Jocaste qui s’avance hors du palais ; avec son aide, il faut mettre fin à ce différend.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'O malheureux , pourquoi vous livrer à des querelle ? insensées ? Ne rougissez-vous pas de nourrir des haines privées, au milieu des maux qui affligent la pairie entière ? Œdipe, et toi, Créon , rentrez dans le palais, et sur de frivoles prétextes ne suscitez pas des discordes funestes !' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ma sœur , Œdipe, ton époux, me menace des plus cruels traitements ; il me réserve l’un de ces deux maux, m’exiler de ma patrie ou me donner la mort.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Il est vrai ; mais, ô femme, je l’ai surpris tramant d’odieux complots contre ma personne.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Que je sois privé de la lumière, chargé d’imprécations, si j’ai rien fait de ce que tu m’imputes !' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Œdipe, au nom du ciel, crois à sa parole, et surtout au serment par lequel il atteste les dieux, crois-en moi-même, et ces Thébains qui t’entourent.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Strophe 1.) Que ta volonté cède à la raison, ô roi, je t’en supplie.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'En quoi veux-tu donc que je te cède ?' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Sais-tu ce que tu demandes ?' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Oui, je le sais.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Explique donc ce que tu prétends.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'De ne pas déshonorer par une accusation fondée sur d’obscurs soupçons un ami qui s’est voué à tes imprécations.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Sache donc que me faire cette demande, c’est me demander ma mort ou mon exil de ce pays.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Strophe 2.) Non, j’en atteste le soleil, le premier de tous les dieux ! que je périsse abandonné des dieux et des hommes, si j’ai cette pensée. Mais, hélas ! ce qui déchire mon cœur, c’est la ruine de la patrie, c’est de voir vos querelles s’ajouter aux malheurs publics.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Eh bien, qu’il parle, dussé-je périr misérablement, ou être violemment banni de cette ville, et méprisé de tous. Car ce sont vos prières, et non les siennes, qui me touchent de pitié ; pour lui, en quelque lieu qu’il soit, il me sera toujours odieux.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Tout en cédant, tu te montres implacable ; mais tu te haïras toi-même, quand ta colère sera calmée. De pareils caractères trouvent en eux-mêmes leur juste châtiment.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Je partirai, méconnu de toi, mais toujours également honoré de ce peuple.' },
    { k: 'didascalie', t: '(Il sort.)' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Antistrophe 1.) Jocaste, que tardes-tu à emmener Œdipe dans le palais ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Je veux apprendre le motif de leur querelle.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Des soupçons dénués de certitude, au sujet d’un entretien, et le ressentiment d’une accusation injuste.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Tous deux se sont attaqués réciproquement ?' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Oui, vraiment.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Et quels étaient leurs discours ?' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Il suffit, dans la calamité qui désole ce pays, il suffit, selon moi, d’arrêter la querelle où elle en est restée.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Vois-tu où tu en viens, malgré tes intentions honnêtes ? tu abandonnes mes intérêts, et ton affection pour moi se refroidit.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Antistrophe 2.) Œdipe, je l’ai dit, et plus d’une fois ? je serais un insensé, je passerais pour un homme dépourvu de toute prudence, si je t’abandonnais, toi qui, lorsque' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Au nom des dieux, apprends-moi aussi, ô roi, quel sujet a excité à ce point ta colère.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je te dirai, ô femme, car je te révère plus que ces hommes, quels complots Créon a tramés contre moi.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Parle, si tu veux m’expliquer clairement le sujet de la querelle, et ce que tu lui reproches.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Il m’accuse d’être le meurtrier de Laïus.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'T\'accuse-t-il d’après sa conviction personnelle, ou sur le rapport d’ autrui ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Il a suborné un misérable devin ; car pour ce qui le regarde, il s’abstient de toute affirmation.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Toi, maintenant, laisse là tous ces discours, écoute mes paroles, et sache qu’il n’est point de mortel qui possède l’art de la divination. Je t’en donnerai une preuve bien simple. Un oracle dicté, je ne dis pas par Apollon lui-même, mais par ses ministres, prédit autrefois à Laïus que son destin était de périr par la main d’un fils qui naîtrait de nous deux. Et cependant, tel est du moins le bruit répandu, des brigands étrangers l’ont tué, un jour, dans un chemin qui se partage en trois sentiers. Mais l’enfant, après sa naissance, trois jours à peine s’étaient écoulés, que son père, après lui avoir percé les pieds, le fit exposer par des mains étrangères sur une montagne déserte. Ici donc, Apollon n’a pas réalisé cette prédiction, qu’il deviendrait le meurtrier de son' },
    { k: 'ligne', t: 'père, ni celle que Laïus subirait de la main de son fils le sort cruel par lui redouté. Telles étaient cependant les prédictions de l’oracle ; mais ne t’en inquiète point : car les choses qu’un dieu croit utile de chercher, il saura bien les manifester lui-même.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'En écoutant ce récit, ô femme, quels doutes agitent mon esprit incertain ! quel trouble s’empare de mon cœur !' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Quelle inquiétude te bouleverse et te fait parler ainsi ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je crois t’avoir entendu dire que Laïus fut tué dans un chemin qui se partage en trois sentiers.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'On le disait ainsi, et ce bruit n’a pas encore été démenti.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Et en quel pays est le lieu où arriva ce malheur ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'On appelle ce pays la Phocide, c’est l’endroit où les routes de Delphes et de Daulie se rejoignent.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Et combien de temps s’est écoulé depuis cet événement ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Un peu avant le temps où tu devins roi de ce pays, la nouvelle de ce fait fut annoncée à Thèbes.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'O Jupiter ! qu’as-tu résolu de faire de moi ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ne m’interroge pas encore. Mais Laïus, dis-moi, quelle était sa taille, quel était son âge ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Sa taille était élevée, sa tête commençait à blanchir, et ses traits n’étaient pas très-différents des tiens.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Hélas ! malheureux ! sans le savoir, j’ai lancé contre moi-même de terribles imprécations.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Que dis-tu ? je n’ose porter mes regards sur toi.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je tremble que le devin ne soit trop clairvoyant. Mais tu éclairciras mes doutes, si tu ajoutes encore un seul mot.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Vraiment, je frémis ; cependant, ce que tu me demanderas, si je le sais, je te le dirai.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'N’avait-il avec lui qu’une petite escorte, ou marchait-il entouré de gardes nombreux, comme il convient à un roi ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Cinq hommes composaient son escorte, et de ce nombre était le héraut ; un seul char menait Laïus.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Hélas ! hélas ! tout est clair maintenant ! Mais quel est, ô femme, celui qui vous lit ces récits ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Un de ses serviteurs, qui revint seul sain et sauf.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Se trouve-t-il encore aujourd’hui dans le palais ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Non, vraiment ; car à peine de retour à Thèbes, te voyant sur le trône, et Laïus au tombeau, il me supplia,' },
    { k: 'ligne', t: 'en me prenant la main, de l’envoyer àa la campagne, garder les troupeaux, pour être le plus loin possible de l’aspect de cette ville. Je l’y envoyai, car ce fidèle serviteur méritait une plus grande récompense.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Pourrait-on le faire venir promptement auprès de nous ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'La chose est possible ; mais pourquoi as-tu ce désir ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je crains bien, ô femme, d’en savoir déjà trop sur ce qui me fait désirer de le voir.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Il viendra ; mais moi aussi je suis digne d’apprendre ce qui trouble ton cœur, ô roi !' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je ne te refuserai pas, à ce point d’attente cruelle où je suis arrivé. Car à qui pourrais-je mieux le dire qu’à toi, dans la situation critique où je me trouve ?' },
    { k: 'ligne', t: 'J’eus pour père Polybe de Corinthe, et pour mère Mérope, Dorienne. J’étais regardé comme le premier des citoyens de Corinthe, lorsqu’il m’arriva une aventure propre à me surprendre, mais peu digne pourtant des inquiétudes qu’elle me causa. Au milieu d’un festin, un homme dans l’ivresse, au milieu de l’orgie, me reprocha d’être un enfant supposé. Irrité de ce propos, j’eus peine à me contenir tout le jour ; et le lendemain j’allai trouver mon père et ma mère, pour les interroger ; ils s’indignèrent contre celui qui avait proféré cet outrage. Je me réjouissais de leur sympathie ; mais le trait cruel me blessait toujours ; car il était entré profondément dans mon cœur. Je pars à l’insu de mon père et' },
    { k: 'ligne', t: 'de ma mère, pour aller à Delphes. Le dieu, sans tenir aucun compte des questions que j’étais venu lui adresser, me renvoya, en me prédisant, entre autres malheurs affreux et inouïs, que je serais le mari de ma mère, que je mettrais au jour une race exécrable, et que je serais l’assassin de mon père. Après avoir entendu ces paroles, je m’éloignai de Corinthe, pour n’en plus mesurer la distance que par le cours des astres, et je cherchai un pays où je pusse éviter l’accomplissement des terribles oracles. Dans ma marche, j’arrive en ces lieux où tu dis que périt Laïus. À toi, femme, je dirai la vérité. J’étais près de l’endroit où la route se partage en un triple sentier, lorsqu’un héraut, et sur un char un homme semblable à celui que tu m’as dépeint, se présentent devant moi ; le conducteur du char et le vieillard lui-même me repoussent violemment de la route ; dans ma colère, je frappe le conducteur qui me disputait le passage ; le vieillard, me voyant approcher du char, saisit le moment, et me frappe sur la tête de deux coups d’aiguillon. Il en porta la peine ; atteint aussitôt du bâton dont ma main était armée, il est renversé de son char, et roule à mes pieds ; je massacre tous ses compagnons. Or, si cet inconnu a quelque rapport avec Laïus, quel homme est plus malheureux que moi ? quel homme est plus haï des dieux ? Nul étranger, nul Thébain, ne peut désormais me recevoir dans sa maison, ni m’adresser la parole, mais ils doivent me chasser de leurs demeures, et ce n’est point un autre que moi qui a lancé ces imprécations contre moi-même. Et la couche du mort, je l’ai souillée de ces mains qui avaient pris sa vie. Suis-je assez criminel ? ne suis-je pas un monstre impur ? Car il faut m’exiler, et dans mon exil, je ne puis ni revoir les miens, ni mettre le pied sur le sol de ma patrie, où je suis menacé de devenir l’époux de ma mère, et de tuer mon père Polybe, celui qui m’a' },
    { k: 'ligne', t: 'donné le jour et qui m’a élevé. N’est-il pas juste de dire que ces calamités me sont envoyées par une divinité cruelle ? Ne souffrez pas, justes dieux, ne souffrez pas que je voie un pareil jour, mais que je disparaisse du nombre des mortels, avant de voir le malheur m’imprimer une telle souillure !' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'O roi, nous partageons tes craintes ; mais jusqu’à ce que celui qui va venir, ait éclairci tes doutes, conserve l’espoir.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Oui, tout ce qui me reste encore d’espoir repose uniquement sur ce berger que j’attends.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Et lorsqu’il sera venu, quelle est ton espérance ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je vais te le dire : si son langage se trouve d’accord avec le tien, j’échappe à toute imputation.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Qu’as-tu donc entendu dans mes paroles qui ait tant d’importance ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Il assure, dis-tu, que des brigands ont massacré Laïus. Si donc il persiste à dire qu’ils étaient plusieurs, je ne suis point le meurtrier ; car on ne saurait prendre un seul homme pour une troupe. Mais s’il ne parle que d’un voyageur isolé, évidemment c’est moi qui suis l’auteur du crime.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Oui, c’est ainsi qu’il a raconté le fait, sache-le bien, et il ne saurait rétracter ses paroles : la ville, en effet, les a entendues, et non pas moi. Mais dût-il s’écarter de son premier récit, jamais il ne prouvera, ô roi, que tu sois, conformément à l’oracle, le meurtrier de Laïus,' },
    { k: 'ligne', t: 'que Loxias a déclaré devoir périr de la main de mon fils : or, ce fils infortuné n’a pu tuer Laïus, mais il a péri le premier. Aussi, désormais nulle prophétie ne saurait-elle obtenir de moi l’attention la plus légère.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tes réflexions sont justes ; cependant envoie chercher le berger, et ne néglige pas ce soin.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'J’y enverrai sans retard, mais rentrons dans le palais ; car je ne voudrais rien faire qui ne te fût agréable.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Strophe 1.) Puisse-t-il m’être donné de conserver la sainte pureté dans toutes mes actions et mes paroles, et d’obéir à ces lois sublimes, émanées des cieux, dont l’Olympe seul est le père, dont l’origine n’a rien d’humain ni de mortel, et que jamais l’oubli ne peut abolir ! en elles vit la puissance divine, que la vieillesse ne peut atteindre.' },
    { k: 'ligne', t: '(Antistrophe 1.) La licence enfante le tyran ; la licence, après s’être livrée follement à des excès désordonnés et funestes, après être montée au comble de' },
    { k: 'ligne', t: 'l’insolence, retombe dans un précipice d’où elle tente en vain de se relever. Je prie le dieu de ne jamais abandonner une poursuite d’où dépend le salut de Thèbes : je ne cesserai jamais de prendre le dieu pour guide.' },
    { k: 'ligne', t: '(Strophe 2.) Mais si un mortel signale par l’insolence son bras ou sa langue, sans crainte de la Justice vengeresse, sans respect pour les images des dieux, qu’une mort funeste le punisse de ses débauches coupables ! S’il élève sa fortune en violant la justice, si dans son délire il ose se livrer à des actes impies, ou porter une main sacrilège sur les choses saintes, à la vue de ces profanations, quel homme voudra désormais chasser de son âme les traits de la colère ? Car si de telles impiétés sont honorées, qu’ai-je besoin de révérer le culte des dieux ?' },
    { k: 'ligne', t: '(Antistrophe 2.) Je n’irai plus porter mes vœux dans le sanctuaire inviolable situé au centre de la terre, ni aux temples d’Abes, ou d’Olympie, si ces oracles ne se vérifient d’une manière éclatante aux yeux de tous les mortels. Mais, ô Jupiter, souverain des cieux, si c’est avec raison que l’on te nomme maître du monde, ne permets pas que rien échappe à tes regards et à ton éternel empire. Car les antiques oracles rendus à Laïus sont méprisés, Apollon a perdu ses honneurs ; c’en est fait du culte des dieux.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Chefs de cette contrée, j’ai conçu la pensée d’aller dans les temples des dieux, et j’ai pris ces guirlandes et ces parfums que vous voyez dans mes mains. Œdipe, en' },
    { k: 'ligne', t: 'effet, abandonne son cœur à mille inquiétudes exagérées ; au lieu de juger en homme sensé des nouveaux oracles par les anciens, il se livre à celui qui parle, dès qu’on parle des choses terribles. Puis donc que mes conseils ne gagnent rien, Apollon, dieu Protecteur, toi dont la statue s’élève devant ce palais, je viens, chargée de ces offrandes, t’implorer, afin que tu amènes une heureuse issue aux terreurs d’OEdipe ; car nous tremblons tous, en le voyant éperdu, comme un pilote au milieu de l’orage.' },
    { k: 'perso', t: 'UN MESSAGER' },
    { k: 'ligne', t: 'Étrangers, pourrais-je savoir de vous où est le palais du roi Œdipe ? ou plutôt dites-moi où il est lui-même, si vous le savez.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Voici son palais, et tu l’y trouveras lui-même, ô étranger ; tu vois devant toi son épouse, la mère de ses enfants.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Puisse-t-elle être heureuse et toujours entourée d’heureux, puisqu’elle est la digne compagne d’Œdipe !' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Je fais les mêmes vœux pour toi, étranger ; car tu le mérites par ton langage obligeant. Mais dis-moi ce qui t’amène en ces lieux, et ce que tu viens nous annoncer ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Quelles sont-elles ? Et qui t’envoie vers nous ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Je viens de Corinthe. Les nouvelles que j’ai à dire vont vous réjouir sans doute, en peut-il être autrement ? mais peut-être vous affliger.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Quoi donc ? comment peuvent-elles produire ce double effet ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Les habitants de Corinthe vont le faire roi, comme déjà le bruit en courait.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Quoi donc ? le vieux Polybe n’est-il plus sur le trône ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Hélas ! non, il est mort, il est dans le tombeau.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Que dis-tu, vieillard ? Polybe est mort ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Que je meure, si je ne dis la vérité !' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'O femme, cours vite l’annoncer à ton maître. Oracles des dieux, qu’êtes-vous devenus ? Œdipe s’est exilé de Corinthe, dans la crainte de tuer son père ; et voilà maintenant que le père a succombé sous les coups du Destin, et non sous les coups de son fils.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Jocaste, épouse chérie, pourquoi m’appelles-tu hors du palais ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Cet homme, quel est-il ? et qu’a-t-il à me dire ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: '11 vient de Corinthe, pour t’annoncer que Polybe, ton père, n’est plus, qu’il est mort.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Que dis-tu, étranger ? raconte-moi toi-même la chose.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Si c’est d’abord là ce que tu désires savoir clairement, je le répète, sois-en certain, il a cessé de vivre.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Sa mort est-elle le résultat d’un crime, ou de la maladie ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Le moindre choc abat le corps des vieillards.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ainsi, le malheureux est mort de maladie ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Ses jours étaient remplis.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ah ! qui voudrait désormais, ô femme, consulter l’autel prophétique de Delphes ou le chant des oiseaux ? D’après leurs prédictions, je devais tuer mon père, mais il est mort, et repose dans le sein de la terre ; et moi, tranquille à Thèbes, je n’ai point tranché ses jours, à moins que le regret de mon départ ne l’ait mis au tombeau ; ainsi seulement je serais l’auteur de sa mort. Ainsi Polybe est aux enfers, emportant avec lui ces vains oracles.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Ne te l’avais-je pas prédit depuis longtemps ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Ne te livre donc plus à ces vaines alarmes.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Eh quoi ! ne dois-je pas redouter la couche de ma mère ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Que peut craindre l’homme, puisqu’il est le jouet de la fortune, et qu’il ne peut lire dans l’avenir ? Le mieux est de vivre au hasard, et comme on peut. Pour toi, ne crains pas d’entrer dans la couche de ta mère. Souvent dans leurs rêves les hommes ont cru partager la couche maternelle. Mais ne tenir nul compte de ces illusions est le plus sûr moyen de vivre tranquille.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tout ce que tu as dit serait fort bien, si ma mère ne vivait encore ; mais tant qu’elle est vivante, malgré tes belles paroles, j’ai sujet de craindre.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Cependant le tombeau de ton père est un grand soulagement.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Très-grand, je le sais ; mais tant que ma mère respire, j’ai lieu de craindre.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Quelle est donc cette femme qui cause vos craintes ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'C’est Mérope, vieillard, celle qui fut l’épouse de Polybe.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Qu’y a-t-il donc qui de sa part vous inspire des craintes ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Un oracle divin, un oracle terrible, ô étranger.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Peux-tu me le dire ? Ou n’est-il pas permis à un étranger de le connaître ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tu le peux. Apollon me prédit un jour que j’étais destiné à m’unir à ma mère, et à verser de mes mains le' },
    { k: 'ligne', t: 'sang de mon père. C’est cette crainte qui m’a tenu longtemps éloigné de Corinthe ; heureux exil ! cependant il est bien doux de voir les auteurs de ses jours.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Ce sont donc là les craintes qui t’exilèrent de notre cité ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ce fut aussi, vieillard, pour ne pas devenir le meurtrier de mon père.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Pourquoi donc ne dissiperais-je pas tes craintes, ô prince ? car je suis venu avec le désir de te servir.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Assurément tu obtiendrais de moi la reconnaissance que tu mérites.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'En effet, je suis venu surtout dans l’espoir d’être récompensé par toi, après ton retour à Corinthe.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Mais je ne retournerai jamais près de ceux qui m’ont donné le jour.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'O mon fils, évidemment tu ne sais pas ce que tu fais.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Comment, ô vieillard ? au nom des dieux explique-toi.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Si c’est là le motif qui t’éloigne de ta patrie.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je crains que l’oracle d’Apollon ne soit reconnu véridique.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'C’est précisément là, vieillard, ce qui me fait toujours trembler.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Tu ne sais donc pas que tu n’as aucun sujet de trembler ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Comment donc, si ce sont là les parents dont je suis né ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'C’est que Polybe ne t’était rien par le sang.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Que dis-tu ? Polybe n’est point mon père ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Non, pas plus que moi-même, mais autant que moi.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Eh ! comment un étranger peut-il être pour moi autant que mon père ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Mais ni lui ni moi ne t’avons donné le jour.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Pourquoi donc m’appelait-il son fils ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Tu es un don, sache-le, que jadis il avait reçu de mes mains.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Et comment a-t-il tant chéri un enfant reçu d’une main étrangère ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Longtemps privé d’enfants, sa tendresse se reporta sur toi.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'M’avais-tu acheté, ou m’as-tu trouvé et donné à lui ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Je t’avais trouvé dans les vallées boisées du Cithéron.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Je conduisais des troupeaux sur ces montagnes.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tu étais donc berger, errant et mercenaire ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Et cependant, mon fils, je fus, dans ce temps-là, ton sauveur.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Quel était mon mal, eu l’état misérable où tu me trouvas ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Les articulations de tes pieds pourraient le témoigner.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Hélas ! pourquoi rappelles-tu ce douloureux souvenir ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Je détachai les liens qui traversaient tes pieds.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tristes et honteuses marques que je gardai de mon enfance !' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Cette triste aventure te fit donner le nom que tu portes.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Au nom des dieux, parle, est-ce mon père, ou ma mère qui me traita ainsi ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ta m’as donc reçu des mains d’un autre ? tu ne m’as pas trouvé toi-même ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Non, mais un autre berger te remit à moi.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Quel est-il ? Pourrais-tu le faire connaître ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'C’était, disait-on, un des serviteurs de Laïus.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'De celui qui fut jadis roi de cette contrée ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Oui. Il avait la garde de ses troupeaux.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Vit-il encore, et pourrais-je le voir ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Vous-mêmes, habitants de ce pays, vous pouvez le savoir mieux que moi.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Y a-t-il quelqu’un de vous, ici présents, qui connaisse le berger dont parle cet homme, et qui l\'ait vu, soit dans la campagne, soit à Thèbes ? qu’il me l’apprenne, car voici le moment de découvrir ce secret.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Je pense que c’est précisément le même berger retiré à la campagne, que tout à l’heure tu désirais voir. Mais Jocaste, que voici, pourrait le dire mieux que personne.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Femme, penses-tu que le berger que nous avons envoyé chercher tout à l’heure soit celui dont parle cet homme ?' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Quel est celui dont il a parlé ? Ne t’inquiète de rien, et oublie de vaines paroles.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Non, rien ne pourra m’empêcher de rechercher les indices propres à me révéler ma naissance.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Au nom des dieux, si tu tiens encore à la vie, renonce à ces recherches ; j’ai bien assez de tourments.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Rassure-toi. Dussé-je descendre de trois femmes esclaves, cet opprobre ne rejaillira point sur toi.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Crois-moi, cependant, je t’en supplie ; n’en fais rien.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Non, rien ne me fera renoncer à pénétrer ce mystère.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Et pourtant c’est par intérêt pour toi que je te donne le meilleur conseil.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Eh bien ! ces excellents conseils me fatiguent depuis longtemps.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Infortuné ! puisses-tu ne jamais savoir qui tu es !' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'M’amènera-t-on enfin ce berger ? Pour elle, laissez-la se réjouir de son illustre naissance.' },
    { k: 'perso', t: 'JOCASTE' },
    { k: 'ligne', t: 'Hélas ! hélas ! malheureux ! car c’est là le seul nom que je puisse te donner désormais ! et je ne t’en donnerai plus d’autre.' },
    { k: 'didascalie', t: '(Elle sort.)' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Pourquoi donc ton épouse, Œdipe, est-elle sortie, emportée par l’excès de sa douleur ? Je crains bien qu’après ce silence il n’éclate de grands malheurs.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Qu’ils éclatent s’il le faut ! Pour moi, dût ma naissance' },
    { k: 'ligne', t: 'être basse, je persisterai à vouloir la connaître. Elle peut-être, car elle a tout l’orgueil d’une femme, rougit de mon obscure origine. Mais moi, je me reconnais fils de la Fortune, qui m’a comblé de ses bienfaits, et je ne subirai pas l’infamie. Car j’ai la Fortune pour mère, et le cours de ma vie m’a départi tour à tour la misère et la grandeur. Issu d’une telle origine, je ne saurais plus désormais devenir autre que je n’ai été, ni renoncer à connaître ma naissance.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Strophe.) Si je sais lire dans l’avenir, et si mes pressentiments ne m’abusent, j’en atteste l’Olympe, ô Cithéron, demain, la lune, dans son plein, n’aura pas achevé son cours, sans que tu sois honoré par nous, mont sacré de la patrie, comme le père et le nourricier d’Œdipe, et célébré par nos danses pour les services que tu rends à mes rois. Apollon sauveur, exauce mes vœux !' },
    { k: 'ligne', t: '(Antistrophe.) O mon fils, quelle fille des immortels t’a donné le jour, par son union avec le dieu Pan, qui erre sur les montagnes, ou est-ce quelque nymphe amante d’Apollon ? car ce dieu se plaît aussi sur les collines aux riches pâturages. Ou bien le dieu du Cyllène, ou Bacchus, qui habite la cime des monts, t’aurait-il' },
    { k: 'ligne', t: 'reçu d’une des nymphes de l’Hélicon, avec lesquelles il aime à folâtrer ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Vieillard, si je puis former des conjectures sur un homme que je n’ai jamais vu, voici sans doute le berger que nous attendons depuis longtemps. Son grand âge, en effet, s’accorde bien avec ce qu’on dit de lui, et surtout je crois reconnaître mes serviteurs qui l’amènent ; mais toi, tu pourrais en parler avec plus de certitude que moi, si tu as déjà vu ce berger.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'En effet, je le connais ; car Laïus n’avait pas de serviteur plus fidèle, dans sa condition de berger.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Toi d’abord, étranger de Corinthe, est-ce là celui dont tu nous parlais ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'C’est lui-même que tu vois.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Vieillard, regarde-moi en face, et réponds à toutes mes demandes. Tu étais au service de Laïus ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'J’étais son esclave, non acheté, mais élevé dans son palais.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Quel était ton emploi, ou ton genre de vie ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Je passais la plus grande partie de mon temps à conduire ses troupeaux.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Quels étaient les lieux que tu fréquentais le plus ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Te souviens-tu donc d’y avoir vu cet homme ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Que faisait-il ? de quel homme parles-tu ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'De celui qui est devant tes yeux ; ne l’as-tu jamais rencontré ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Non, autant du moins que mes souvenirs me permettent de l’affirmer.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Il n’y a rien d’étonnant, ô maître ; mais je rappellerai clairement ses souvenirs effacés, car je n’en doute pas, il sait très-bien que dans les pâturages du Cithéron, il conduisait deux troupeaux, et moi je n’en avais qu’un ; nous restâmes ensemble trois mois entiers, depuis la fin du printemps jusqu’au lever de l’arcture ; et l’hiver, nous ramenâmes nos troupeaux, moi, dans mes bergeries, lui, dans celles de Laïus. Y a-t-il dans tout ce que je dis quelque chose qui ne soit pas exact ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Tu dis vrai, quoiqu’il y ait bien longtemps.' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Dis-moi maintenant, te souviens-tu qu’alors tu me remis un enfant, pour l’élever comme le mien ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Que veux-tu dire ? pourquoi me fais-tu cette question ?' },
    { k: 'perso', t: 'LE MESSAGER' },
    { k: 'ligne', t: 'Voici devant toi, mon cher, celui qui était alors enfant.' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ne le maltraite pas, vieillard ; c’est ton langage qui mérite le blâme, bien plus que le sien.' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Qu’ai-je donc fait de mal, ô le meilleur des maîtres ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tu ne réponds pas sur cet enfant dont il te parle.' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Il ne sait ce qu’il dit, mais il prend une peine inutile.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Et toi, parleras-tu de bonne grâce ? sinon, ce sera de force.' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Au nom des dieux, ne maltraite pas un vieillard !' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Qu’au plus tôt on lui attache les mains derrière le dos.' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Malheureux ! et pourquoi ? que veux-tu apprendre ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Lui as-tu remis cet enfant dont il parle ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Oui, je le lui donnai, et que ne suis-je mort ce jour-là !' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'C’est ce qui t’arrivera aujourd’hui, si tu ne dis la vérité.' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Ce sera bien plutôt si je parle, que je périrai.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Cet homme, je le vois, cherche des délais.' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Non, vraiment, car j’ai déjà dit que je le lui avais remis.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Il n’était pas à moi, je l’ai reçu de quelqu’un.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'De quel habitant de la ville, et de quelle maison ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Au nom des dieux, mon maître, ne me questionne pas davantage.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Tu es mort, si je répète ma question.' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Eh bien ! c’était quelqu’un de la maison de Laïus.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Esclave, ou de la famille du roi ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Malheur à moi ! me voilà revenu à ce secret, le plus terrible à dire.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Et le plus terrible à entendre. N’importe, je veux l’apprendre.' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'On le disait fils de Laïus ; mais celle qui est dans le palais, ton épouse, pourrait mieux que personne dire ce qui en est.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Est-ce donc elle qui te le remit ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Elle-même, ô roi !' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Dans quelle intention ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Pour le faire périr.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Elle qui l’avait enfanté ! Ah ! malheureuse !' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Que disaient-ils ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'Qu’il tuerait les auteurs de ses jours.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Pourquoi donc l’as-tu remis à ce vieillard ?' },
    { k: 'perso', t: 'LE BERGER' },
    { k: 'ligne', t: 'J’en eus pitié, mon maître ; je crus qu’il l’emporterait sur une terre étrangère, dans sa patrie ; il l’a conservé pour les plus grands malheurs ; car si tu es celui dont il parle, tu es le plus infortuné des hommes.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Hélas ! hélas ! tout est révélé maintenant. O lumière ; je te vois pour la dernière fois. Il est trop vrai ! par ma naissance, par mon hymen incestueux, par mon affreux parricide, j’ai violé les plus saintes lois de la nature.' },
    { k: 'didascalie', t: '(Il sort.)' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: '(Strophe 1.) O race des mortels, combien, à mon sens, votre vie ressemble au néant ! car l’homme le plus heureux a-t-il plus que l’apparence du bonheur ? et encore cette apparence est bientôt évanouie ! Aussi, instruit par ton exemple et par ta destinée, ô malheureux Œdipe, je ne crois plus au bonheur d’aucun mortel.' },
    { k: 'ligne', t: '(Antistrophe 1.) Dans l’essor de ta prodigieuse fortune, tu t’élevas au faîte de la prospérité ; tu nous délivras de la vierge aux griffes crochues et aux énigmes funestes,' },
    { k: 'ligne', t: 'et tu apparus à ma patrie comme un rempart contre la mort ; puis tu fus appelé notre roi, et, environné des plus grands honneurs, tu régnas sur la puissante ville de Thèbes.' },
    { k: 'ligne', t: '(Strophe 2.) Et maintenant, d’après tout ce que j’entends, quel homme est plus malheureux que toi ? quel autre fut précipité par les vicissitudes de la vie dans un tel abîme de misères et de calamités ? Illustre Œdipe, toi qui fus reçu dans le même sein, à la fois comme fils et comme époux, comment, comment donc ce lit nuptial, qui fut celui de ton père, a-t-il pu si longtemps te porter en silence ?' },
    { k: 'ligne', t: '(Antistrophe 2.) Le temps, à qui rien n’échappe, a surpris, malgré toi, ton opprobre, et condamné un hymen contre nature, où le fils a rendu mère celle qui l’avait enfanté. O fils de Laïus, puissé-je ne t’avoir jamais connu, car ma douleur s’exhale sur toi en cris lamentables ! Mais, pour dire la vérité, si je te dois la vie, je te dois aussi la mort.' },
    { k: 'perso', t: 'UN SECOND MESSAGER' },
    { k: 'ligne', t: 'O vous qui êtes les habitants les plus respectés de Thèbes, quels malheurs vous allez entendre, quels malheurs vous allez voir, quelle affliction va vous saisir, si l’amour de la patrie vous intéresse encore à la famille des Labdacides ! Non, les eaux de l’Ister ni celles du Phase ne suffiraient pas pour laver les souillures cachées' },
    { k: 'ligne', t: 'dans ce palais ; mais voici d’autres désastres volontaires qui vont paraître au grand jour. Ah ! de tous les maux, les plus cuisants sont ceux qu’on s’est infligés soi-même.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Rien ne manque à l’horreur de ceux que nous connaissons déjà ; que peux-tu y ajouter encore ?' },
    { k: 'perso', t: 'LE SECOND MESSAGER' },
    { k: 'ligne', t: 'Un mot me suffira pour le dire, et à vous pour l’apprendre. Jocaste est morte.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'O l’infortunée ! Quelle a été la cause de sa mort ?' },
    { k: 'perso', t: 'LE SECOND MESSAGER' },
    { k: 'ligne', t: 'Elle-même s’est tuée de ses propres mains. Ce que cette mort a de douloureux vous échappe, car ce spectacle n’est pas sous vos yeux ; cependant, autant que j’en conserve le souvenir, je vous dirai les souffrances de cette infortunée. Agitée d’une sombre fureur, dès qu’elle eut franchi le seuil du palais, elle courut droit à la couche nuptiale, arrachant sa chevelure de ses deux mains ; une fois entrée, elle ferme violemment les portes en dedans, évoque l’ombre de Laïus, lui rappelant le souvenir de ce fils oublié, de la main duquel il devait périr lui-même, en laissant une mère qui donnerait le jour à des enfants incestueux. Elle arrose de ses larmes cette couche où, doublement malheureuse, elle eut un époux de son époux, et des enfants de son enfant. Je ne vis pas ensuite comment elle a péri ; car Œdipe se précipita à grands cris, ce qui nous empêcha de voir la mort de Jocaste ; mais nos regards se tournent vers lui, qui errait çà et là. Dans cet égarement, il nous demande une épée, et veut savoir où est l’épouse qui n’est pas son' },
    { k: 'ligne', t: 'épouse, celle dont le sein maternel, après l’avoir porté, porta aussi ses enfants. Dans sa fureur, un dieu la lui montra, car ce ne fut aucun de nous qui étions là présents. Poussant de grands cris, et comme si quelqu’un le guidait, il s’élance contre les portes, fait sauter les battants de leurs gonds, et s’élance dans l’appartement. Là, nous voyons Jocaste, encore suspendue au lien fatal qui a terminé ses jours : à cette vue, l’infortuné rugit comme un lion, et détache le lien funeste ; mais quand le corps de la malheureuse fut gisant à terre, alors on vit un affreux spectacle : arrachant les agrafes d’or de la robe qui couvrait Jocaste, Œdipe en frappe ses yeux, parce que, s’écriait-il, ils n’avaient vu ni ses malheurs, ni ses crimes, et que, désormais dans les ténèbres, ils ne verraient plus ceux qu’il ne devait point voir, ils ne reconnaîtraient plus ceux qu’il lui serait doux de reconnaître. En parlant ainsi, il frappe et déchire à plusieurs reprises ses paupières ; en même temps ses yeux ensanglantés arrosaient son visage, et ce n’étaient pas seulement des gouttes qui s’en échappaient, mais c’était une pluie noire et comme une grêle de sang. Tels sont les maux communs à l’un et à l’autre ; c’est ainsi que l’époux et la femme confondirent leur infortune. Heureux autrefois, ils jouissaient d’un bonheur mérité ; mais aujourd’hui, les gémissements, le désespoir, l’opprobre et la mort, aucune espèce de malheur n’y manque.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Et maintenant, l’infortuné a-t-il quelque relâche à ses souffrances ?' },
    { k: 'perso', t: 'LE SECOND MESSAGER' },
    { k: 'ligne', t: 'Il crie d’ouvrir les portes, et d’exposer aux yeux de tous les Thébains ce parricide, ce fils dont la mère... Je ne dois pas répéter ces blasphèmes. Il est résolu de s’exiler de cette terre, et ne veut plus rester dans ce' },
    { k: 'ligne', t: 'palais, sous le poids des malédictions qu’il a lancées contre lui-même. Cependant il a besoin de secours et d’un guide, car ses douleurs surpassent ses forces. Tu vas en être témoin ; voici les portes qui s’ouvrent, tu vas voir un spectacle qui attendrirait même un ennemi.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'O spectacle horrible, le plus horrible qui ait jamais frappé les yeux ! ô malheureux ! quel délire s’est emparé de toi ? quel est le dieu qui a fait fondre les calamités les plus cruelles sur ta destinée ? Je ne puis même supporter ta vue, moi qui aurais tant de questions à te faire, tant de choses à apprendre de toi ou à contempler en toi ! je ne le puis, tant ton aspect me fait frissonner !' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Hélas ! hélas ! malheureux que je suis ! en quels lieux me portent mes pas ? où s’égarent les sons de ma voix ? O fortune, où m’as-tu précipité ?' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Dans des horreurs qu’on ne peut ni voir ni entendre.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: '(Strophe 1.) O ténèbres, nuage odieux, implacable, qui m’enveloppes sans retour d’une impénétrable obscurité ! Malheur à moi, mille fois malheur ! De quels aiguillons me déchirent à la fois ma douleur présente et le souvenir de mes calamités !' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Parmi tant de maux, il n’est pas étonnant que tu aies doublement à gémir et doublement à souffrir.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: '(Antistrophe 1.) O mon ami, tu restes donc toujours' },
    { k: 'ligne', t: 'fidèle à me servir ? car tu oses encore prendre soin de moi, tout aveugle que je suis. Hélas ! hélas ! Je ne me trompe pas, et, malgré les ténèbres qui m’environnent, j’ai du moins reconnu ta voix.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'O terrible résolution ! Comment as-tu eu le courage de t’arracher ainsi les yeux ? Quel dieu a poussé ton bras ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: '(Strophe 2.) Apollon, mes amis, oui, Apollon est la cause de mes maux, de mes cruelles souffrances. Mais ce n’est pas sa main qui m’a frappé, c’est moi seul ; car que me servait de voir, lorsque je ne pouvais rien voir que d’affligeant ?' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Les choses sont en effet comme tu le dis.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: '(Strophe 3.) Que pourrais-je donc voir encore, aimer, entendre avec plaisir, ô mes amis ? Chassez-moi de cette terre au plus vite ; délivrez-la de ce fléau, de ce monstre chargé de la haine des hommes et des dieux.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'O Œdipe, doublement malheureux et par ta misère, et par le sentiment que tu en as, plût aux dieux que je ne t’eusse jamais connu !' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: '(Antistrophe 2.) Périsse celui qui me délivra des entraves douloureuses de mes pieds, m’arracha à la mort et me sauva ! car alors j’aurais péri, et je ne serais pas pour mes amis et pour moi un éternel sujet de douleur.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Moi aussi je m’unis à ton vœu.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: '(Antistrophe 3.) Je n’aurais pas été le meurtrier de mon père, ni l’époux de celle qui m’a donné le jour. Mais aujourd’hui, abandonné des dieux, fils de parents impurs, j’ai eu des enfants de celle même dont je suis né ;' },
    { k: 'ligne', t: 'et. s’il est encore des maux plus horribles, ils ont fondu sur Œdipe.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Je ne sais si je dois approuver ta résolution ; car il eût mieux valu pour toi ne plus vivre, que vivre aveugle.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ce que j’ai fait était ce que j’avais de mieux à faire, ne cherche point à me persuader et ne me donne plus de conseils. De quels yeux, en effet, si j’étais descendu clairvoyant aux enfers, regarderais-je un père, une mère infortunée, sur lesquels j’ai commis des crimes que la mort la plus ignominieuse ne saurait expier ? Diras-tu qu’il m’eût été doux de voir croître ces enfants sous mes yeux, quelle que soit leur naissance ? Non, jamais je n’aurais pu supporter leur vue. Je ne pourrais plus voir cette ville, ces murs, ces images sacrées des dieux, que moi seul entre les Thébains je me suis interdits à moi-même, lorsque j’ordonnai à tous de bannir le coupable, moi, l’impie, que les dieux ont désigné comme l’être impur, et issu du sang de Laïus. Après avoir ainsi révélé mon opprobre, aurais-je pu en voir les témoins d’un œil assuré ? Non, certes. Mais que ne puis-je encore fermer en moi les sources de l’ouïe ! je ne manquerais pas de clore toutes les parties de mon corps, afin d’être à la fois aveugle et sourd. En effet, n’avoir pas le sentiment, de son malheur est une consolation. O Cithéron ! pourquoi m’as-tu donné asile ? pourquoi, du moins, ne m’as-tu pas sur-le-champ donné la mort, pour que jamais le secret de ma naissance ne fût révélé aux hommes ? O Polybe ! ô Corinthe ! palais antique, que j’appelais celui de mon père, quel amas d’impuretés vous nourrissiez en moi, sous ces dehors brillants ! Maintenant je me trouve être un coupable, issu d’une race coupable. O triple chemin, sombre vallée, forêt témoin de mon crime, étroit sentier à l’embranchement des trois routes, qui' },
    { k: 'ligne', t: 'avez bu le sang de mon père versé par mes mains, avez-vous gardé le souvenir des crimes que je commis alors, et de ceux que je commis ensuite, une fois arrivé dans Thèbes ? O hymen, hymen funeste ! tu m’as donné la vie, et, après me l’avoir donnée, tu fis rentrer mon sang dans ces mêmes flancs où je fus porté, et par là tu produisis des pères, des frères, des fils, criminel assemblage, des femmes, des épouses, des mères, et tout ce que les hommes virent jamais de plus abominable. Mais c’en est trop, craignons de redire ce qu’il est horrible de faire ; au nom des dieux, hâtez-vous, cachez-moi dans quelque terre écartée ; arrachez-moi la vie, précipitez-moi dans la mer, en des lieux où vous ne me verrez plus. Approchez, daignez toucher un malheureux ; croyez-moi, ne craignez rien ; de tels maux ne sauraient atteindre nul autre mortel que moi.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Mais voici à propos Créon, qui pourra satisfaire tes demandes et t’aider de ses conseils ; car il reste seul chargé de veiller à ta place sur ce pays.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Hélas ! que pourrais-je donc lui dire ? quel droit ai-je d’espérer en lui ? je me suis montré naguère si injuste à son égard !' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Je ne viens point, Œdipe, insulter à tes maux, et te reprocher aucune des anciennes offenses. Mais vous, Thébains, si vous ne respectez plus les hommes, au' },
    { k: 'ligne', t: 'moins craignez de souiller la lumière vivifiante de ce sacré Soleil, en exposant à tous les yeux cet objet impur que ni la terre, ni l’air, ni les eaux ne peuvent plus recevoir. Faites-le donc rentrer au plus tôt dans le palais. Les parents doivent seuls être témoins des maux d’un parent, seuls ils peuvent entendre ses plaintes.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Au nom des dieux, puisque, trompant mon attente, tu payes de la plus généreuse amitié mes cruels outrages, écoute-moi, car c’est dans ton intérêt que je parlerai, et non dans le mien.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Et quelle est la chose que tu désires si vivement obtenir de moi ?' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Chasse-moi au plus tôt de cette terre, en des lieux où je ne puisse converser avec aucun mortel.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Je l’aurais fait, n’en doutez point, si je ne voulais auparavant consulter le dieu.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Mais son oracle est assez manifeste, il a ordonné de faire périr le parricide, l’impie.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Sans doute, il l’a dit ; toutefois, dans la situation critique où nous sommes, il vaut mieux l’interroger sur ce qu’il faut faire.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Tes malheurs en effet prouveraient assez qu’il faut croire le dieu.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Je te le demande aussi, et je t’en conjure, prépare pour celle dont le corps est étendu dans ce palais les funérailles que tu jugeras convenables ; c’est un devoir qu’il te sera honorable de rendre aux tiens. Quant à moi, il n’y a pas lieu de penser que jamais la ville de mes pères veuille me posséder vivant. Laisse-moi donc aller sur les montagnes, sur le Cithéron, ma patrie, que ma mère et mon père m’avaient désignée dès ma naissance pour tombeau, afin que je meure où ils voulurent me faire périr. Toutefois je prévois trop bien que ni la maladie ni aucun autre accident ne doit terminer ma vie ; car je n’aurais pas échappé à la mort, si je n’étais réservé à quelque malheur affreux. Eh bien ! que ma destinée s’accomplisse ! Quant à mes enfants..., je ne te recommande point mes fils, ô Créon ! ils sont hommes, et, partout où ils seront, ils ne manqueront de rien ; mais je laisse deux filles dignes de pitié ; autrefois elles s’asseyaient à ma table, et je ne touchais à aucun aliment dont elles n’eussent leur part ; veille sur elles, et surtout permets-moi de les toucher encore, et de pleurer avec elles notre misère.' },
    { k: 'ligne', t: 'Créon, roi dont la naissance est pure, Créon ! ah ! s’il m’était permis de les toucher de mes mains, il me semblerait les voir encore... Que dis-je ? ne les entends-je pas verser des larmes ? O filles chéries ! la pitié de Créon vous aurait-elle envoyées auprès de moi ? ne me trompé-je pas ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Tu ne te trompes pas ; c’est moi qui les ai fait venir, quand j’ai connu le désir que tu avais de les voir comme' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ah ! puisses-tu être heureux ! puissent les dieux, pour prix de ce bienfait, veiller sur toi mieux que sur moi ! O mes filles, où êtes-vous ? Venez ici, venez toucher ces mains fraternelles, qui ont réduit à ce triste état les yeux jadis brillants de votre père ; malheureux, qui, sans le savoir, sans me connaître, vous engendrai dans les mêmes flancs qui m’avaient porté ! Je pleure sur vous, car je ne puis vous voir, en songeant aux amertumes qui attendent la vie qui vous reste à passer au milieu des hommes. À quelle assemblée des citoyens, à quelle fête pourrez-vous assister, sans en rapporter dans votre demeure, au lieu des plaisirs du spectacle, des yeux baignés de larmes ? Et quand le temps de l’hymen sera venu pour vous, quel mortel, ô mes filles, osera associer à son nom tout l’opprobre répandu sur mes parents et sur les vôtres ? Et en effet, que manque-t-il à vos calamités ? Votre père a assassiné son père, il a rendu mère celle qui l’avait enfanté, et il vous a engendrées dans le sein où lui-même il reçut la vie : vous entendrez tous ces reproches, et alors qui osera vous épouser ? Personne, ô mes enfants, personne ; mais le célibat et la stérilité seront votre partage. O fils de Ménécée ! puisque tu es le seul père qui leur reste (car leur mère et moi nous ne sommes plus), ne les livre point avec dédain à une vie errante dans l’abandon et la mendicité, elles qui sont issues de ton sang ; n’égale point leur infortune à mes malheurs. Aie pitié de leur jeunesse et de leur délaissement, elles n’ont que toi pour soutien. Promets-le, généreux Créon, touche-moi de ta main. J’aurais bien des conseils à vous donner, mes enfants, si vous pouviez les comprendre ; mais maintenant, demandez, pour moi, de passer ma vie où le destin veut que je vive, et, pour vous, puisse votre vie être plus heureuse' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'C’est assez verser de pleurs ; rentre dans le palais.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Il faut obéir, quoiqu’à regret.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'L’à-propos fait le mérite des choses.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Sais-tu à quelle condition j’y vais ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Dis-le-moi, pour que je le sache.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'C’est que tu me chasses loin de cette terre.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Tu me demandes ce qui dépend du dieu.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Mais je suis l’objet de la haine des dieux.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ainsi tes vœux seront bientôt remplis.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Dis-tu vrai ?' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Je ne dis point ce que je ne pense pas.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Eh bien ! emmène-moi d’ici.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Viens donc, mais quitte ces jeunes filles.' },
    { k: 'perso', t: 'ŒDIPE' },
    { k: 'ligne', t: 'Ah ! ne me les arrache pas.' },
    { k: 'perso', t: 'CRÉON' },
    { k: 'ligne', t: 'Ne demande pas à satisfaire tous tes désirs ; tes succès ont peu profité à ton bonheur.' },
    { k: 'perso', t: 'LE CHŒUR' },
    { k: 'ligne', t: 'Voyez, Thébains, cet Œdipe qui expliqua les énigmes du sphinx, et qui, devenu puissant, n’a jamais regardé' },
    { k: 'ligne', t: 'avec envie la prospérité de ses concitoyens, voyez en quel abîme de misère il est tombé. Sachez donc qu’aucun mortel, tant qu’il n’a pas encore vu son dernier jour, ne saurait être appelé heureux, s’il n’a atteint le terme de sa vie sans avoir éprouvé d’infortune.' },
  ],
};

export default texte;
